1	/** Coordinates of a live cell on an infinite grid, as `[x, y]`. */
2	export type Cell = [x: number, y: number];
3	
4	const toKey = (x: number, y: number): string => `${x},${y}`;
5	const fromKey = (key: string): Cell =>
6	  key.split(",").map(Number) as Cell;
7	
8	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
9	  [-1, -1], [0, -1], [1, -1],
10	  [-1,  0],          [1,  0],
11	  [-1,  1], [0,  1], [1,  1],
12	];
13	
14	/**
15	 * Computes the next Game of Life generation from the current live cells.
16	 *
17	 * Algorithm: tally how many live neighbors each candidate cell has (every
18	 * neighbor of a live cell is a candidate), then apply Conway's rules:
19	 *   - A cell with exactly 3 neighbors is alive next tick (birth or survival).
20	 *   - A live cell with exactly 2 neighbors also survives.
21	 *   - All other cells are dead.
22	 */
23	export function nextGeneration(cells: Cell[]): Cell[] {
24	  const liveKeys = new Set<string>();
25	  const neighborCounts = new Map<string, number>();
26	  for (const [x, y] of cells) {
27	    liveKeys.add(toKey(x, y));
28	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
29	      const neighborKey = toKey(x + dx, y + dy);
30	      neighborCounts.set(neighborKey, (neighborCounts.get(neighborKey) ?? 0) + 1);
31	    }
32	  }
33	  const isAliveNextTick = (key: string, count: number): boolean =>
34	    count === 3 || (count === 2 && liveKeys.has(key));
35	  const nextCells: Cell[] = [];
36	  for (const [key, count] of neighborCounts) {
37	    if (isAliveNextTick(key, count)) nextCells.push(fromKey(key));
38	  }
39	  return nextCells;
40	}
41

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies (underpopulation) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("rule 1 underpopulation: two adjacent cells both die — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("block still life survives unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const next = nextGeneration(block);
17	    expect(next).toHaveLength(4);
18	    expect(next).toEqual(expect.arrayContaining(block));
19	  });
20	  it("rule 2 survival: live cell with 2 neighbors survives — center of vertical 3-line survives", () => {
21	    const cells: [number, number][] = [[0, 0], [0, 1], [0, 2]];
22	    const next = nextGeneration(cells);
23	    expect(next).toEqual(expect.arrayContaining([[0, 1]]));
24	  });
25	  it("rule 3 overpopulation: center cell with 4+ neighbors dies — full 3x3 center dies", () => {
26	    const cells: [number, number][] = [
27	      [0, 0], [1, 0], [2, 0],
28	      [0, 1], [1, 1], [2, 1],
29	      [0, 2], [1, 2], [2, 2],
30	    ];
31	    const next = nextGeneration(cells);
32	    expect(next).not.toEqual(expect.arrayContaining([[1, 1]]));
33	  });
34	  it("rule 4 reproduction: dead cell with exactly 3 neighbors becomes alive — L-shape produces new cell at (1,1)", () => {
35	    const cells: [number, number][] = [[0, 0], [1, 0], [0, 1]];
36	    const next = nextGeneration(cells);
37	    expect(next).toEqual(expect.arrayContaining([[1, 1]]));
38	  });
39	  it("blinker oscillates vertical to horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
40	    const cells: [number, number][] = [[0, 0], [0, 1], [0, 2]];
41	    const next = nextGeneration(cells);
42	    expect(next).toHaveLength(3);
43	    expect(next).toEqual(expect.arrayContaining([[-1, 1], [0, 1], [1, 1]]));
44	  });
45	  it("handles negative coordinates — block at negative offset survives", () => {
46	    const block: [number, number][] = [[-5, -5], [-4, -5], [-5, -4], [-4, -4]];
47	    const next = nextGeneration(block);
48	    expect(next).toHaveLength(4);
49	    expect(next).toEqual(expect.arrayContaining(block));
50	  });
51	});
